     4|//
     5|//  Full-screen IVX Reels matching ivxholding.com (ivx-reels.js).
     6|//  Same feed, same filters, same engagement rail, same deal CTAs.
     7|//
     8|
     9|import SwiftUI
    10|import AVKit
    11|
    12|struct ProjectReelsView: View {
    13|    @State private var model = ProjectReelsViewModel()
    14|    @State private var activeIndex: Int = 0
    15|    @State private var isMuted = true
    16|    @State private var selectedDeal: JVDeal?
    17|    @State private var channel: ReelChannel = .all
    18|    @Environment(\.dismiss) private var dismiss
    19|
    20|    var body: some View {
    21|        ZStack {
    22|            Color.black.ignoresSafeArea()
    23|            content
    24|            VStack(spacing: 0) {
    25|                header
